async function load(){const n=document.getElementById('node').value;const res=await fetch(`../../reports/live-hotpocket-cluster/${n}/projection.json`).catch(()=>null);const data=res&&res.ok?await res.json():{status:'waiting for live projection'};document.getElementById('status').textContent=`tick/lclSeqNo: ${data.tick??'n/a'} replay: ${data.replay_status??'n/a'} roots: ${data.state_root??'n/a'}`;document.getElementById('state').textContent=JSON.stringify(data,null,2)}document.getElementById('node').addEventListener('change',load);load();setInterval(load,3000);
